#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PersistentAgentRequest {
    // Base ExecutorRequest fields (0-4)
    pub executor: Address,
    pub encrypted_secrets: Vec<Bytes>,
    pub ttl: u64,
    pub secret_signature: Vec<Bytes>,
    pub user_public_key: Bytes,

    // Phase 2 config (5)
    /// Phase 2 deadline offset from Phase 1 settlement block
    pub max_spawn_block: u64,

    // Delivery config (6-11)
    pub delivery_config: DeliveryConfig,

    // LLM config (12-14)
    pub provider: LLMProvider,
    pub model: String,
    pub llm_api_key_ref: String,

/// Response from Persistent Agent spawn via precompile 0x0820
#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct PersistentAgentResponse {
    /// Unique identifier for the spawned agent instance
    pub instance_id: String,
    /// URL endpoint to interact with the agent
    pub gateway_url: String,
    /// Docker container ID running the agent
    pub container_id: String,
    /// DA manifest CID for state checkpoint (empty if none)
    pub checkpoint_cid: String,
    /// Error message if spawn failed (empty on success)
    pub error_message: String,
}

